impl Solution { pub fn check_if_prerequisite(n: i32, pre: Vec<Vec<i32>>, queries: Vec<Vec<i32>>) -> Vec<bool> { let mut black_matrix = vec![vec![false; n as usize]; n as usize]; for p in pre { black_matrix[p[0] as usize][p[1] as usize] = true; } for k in 0..n as usize { for i in 0..n as usize { for j in 0..n as usize { black_matrix[i][j] = black_matrix[i][j] || (black_matrix[i][k] && black_matrix[k][j]); } } } queries.into_iter().map(|q| black_matrix[q[0] as usize][q[1] as usize]).collect() } }